def fibonacci(n):
    # Base Cases
    if n == 0:
        return 0
    if n == 1 or n == 2:
        return 1

    # Strong Induction: Uses fibonacci(n-1) AND fibonacci(n-2)
    return fibonacci(n - 1) + fibonacci(n - 2)

# Proof by Strong Induction:
# Base Cases: fibonacci(0)=0, fibonacci(1)=1, fibonacci(2)=1 ✓
# Inductive Hypothesis: fibonacci(i) = F_i for all i ≤ k
# Inductive Step: fibonacci(k+1) = fibonacci(k) + fibonacci(k-1)
#                               = F_k + F_{k-1}
#                               = F_{k+1} (by Fibonacci property) ✓
